const headers = $input.item.json.headers || {};
const body = $input.item.json.body || {};
const auth = headers['authorization'] || headers['Authorization'] || '';
const token = auth.toLowerCase().startsWith('bearer ') ? auth.slice(7).trim() : '';
if (!token) return { json: { _unauthorized: true, status: 401, error: 'Missing session token' } };
const validProducts = ['term_life','whole_life','critical_illness','disability','auto','home','commercial'];
const validChannels = ['whatsapp','sms','email','web'];
if (!body.lead_id || !body.product_type) return { json: { _empty: true, status: 400, error: 'lead_id and product_type required' } };
if (validProducts.indexOf(body.product_type) < 0) return { json: { _empty: true, status: 400, error: 'product_type must be one of ' + validProducts.join(',') } };
const channel = body.channel || 'whatsapp';
if (validChannels.indexOf(channel) < 0) return { json: { _empty: true, status: 400, error: 'channel must be one of ' + validChannels.join(',') } };
return { json: {
  token: token,
  lead_id: body.lead_id,
  client_id: body.client_id || null,
  product_type: body.product_type,
  channel: channel
} };

const rows = $input.item.json;
const row = Array.isArray(rows) ? (rows[0] || null) : (rows && (rows.user_id || rows.id) ? rows : null);
if (!row) return { json: { _unauthorized: true, status: 401, error: 'Invalid or expired session' } };
const allowed = ['advisor','mga_principal','supervisor','admin'];
if (allowed.indexOf(row.user_role) < 0) return { json: { _unauthorized: true, status: 403, error: 'Role not permitted' } };
const i = $('Extract Inputs').item.json;
return { json: {
  _ok: true,
  advisor_id: row.id || row.user_id,
  user_role: row.user_role,
  client_id: i.client_id || row.client_id || null,
  lead_id: i.lead_id,
  product_type: i.product_type,
  channel: i.channel
} };

const ctx = $('Check Role').item.json;
const rows = $input.item.json;
const lead = (Array.isArray(rows) ? rows[0] : rows) || {};
const firstName = lead.first_name || (lead.full_name || '').split(' ')[0] || 'there';

const systemPrompt = [
  'You are the Crystallux AI Suitability Interviewer for the INSURANCE vertical (vertical_id=insurance).',
  'Product under consideration: ' + ctx.product_type,
  'You are starting a conversational suitability assessment over ' + ctx.channel + '.',
  'Lead context: ' + firstName + (lead.company ? ' at ' + lead.company : '') + (lead.city ? ' in ' + lead.city : ''),
  '',
  'Output strictly JSON. Schema:',
  '{',
  '  "question":              "<one short question, conversational, friendly tone>",',
  '  "expected_answer_type":  "text" | "number" | "choice" | "yes_no",',
  '  "choices":               [ "<option>" ]   // only if expected_answer_type=choice',
  '}',
  '',
  'Rules:',
  '- Single question. ONE thing at a time.',
  '- Open with a warm acknowledgement (1 short sentence) BEFORE the question.',
  '- For ' + ctx.product_type + ', start with the highest-leverage question for needs determination (e.g. dependents/income for term_life; existing coverage for whole_life; occupation/income for disability; vehicle details for auto; mortgage status for home; revenue/employee count for commercial).',
  '- For SMS/WhatsApp keep total reply under 320 characters.'
].join('\n');

return { json: {
  ctx: ctx,
  lead: lead,
  claude_payload: {
    model: 'claude-sonnet-4-5-20250929',
    max_tokens: 400,
    temperature: 0.4,
    system: systemPrompt,
    messages: [ { role: 'user', content: 'Generate the opening question now. JSON only.' } ]
  }
} };

const ctx = $('Build Claude Prompt').item.json.ctx;
const lead = $('Build Claude Prompt').item.json.lead;
const resp = $input.item.json || {};
let text = '';
try { text = (resp.content && resp.content[0] && resp.content[0].text) || ''; } catch (e) {}
let parsed = null;
try { parsed = JSON.parse(String(text).replace(/```json|```/g, '').trim()); } catch (e) {}
if (!parsed || !parsed.question) {
  parsed = { question: 'To get started, can you tell me a bit about your current situation?', expected_answer_type: 'text', choices: [] };
}
const tokens = (resp.usage && (resp.usage.input_tokens + resp.usage.output_tokens)) || 0;

const initialSituation = {
  qa_history: [ { q: parsed.question, a: null, asked_at: new Date().toISOString() } ],
  expected_next: { type: parsed.expected_answer_type, choices: parsed.choices || [] }
};

return { json: {
  insert_row: {
    vertical_id: 'insurance',
    client_id: ctx.client_id,
    lead_id: ctx.lead_id,
    advisor_id: ctx.advisor_id,
    product_type: ctx.product_type,
    channel: ctx.channel,
    client_situation: initialSituation,
    status: 'in_progress'
  },
  question: parsed.question,
  channel: ctx.channel,
  lead_email: lead.email,
  lead_phone: lead.phone,
  client_id: ctx.client_id,
  advisor_id: ctx.advisor_id,
  lead_id: ctx.lead_id,
  tokens: tokens
} };
